mapper.select:
select c.id, c.name, c.room, c.begin_date as beginDate, c.end_date as endDate, c.master_id as masterId, e.name as masterName, c.create_time as createTime, c.update_time as updateTime, case when curdate() <= c.begin_date then '未开班' when curdate() >= c.end_date then '已结课' else '已开班' end as status from clazz c left join emp e on c.master_id = e.id
and c.name like concat('%', #{name}, '%')
and c.end_date >= #{begin}
and c.begin_date <= #{end}
order by c.update_time desc

mapper.update:
update clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject},
where id = #{id}
